"""
Pytest test suite for Lab Test Ordering Requirements
Requirement: A clinician shall order a lab test; orders shall route to the patient's
preferred lab when available.
Covers: happy path, preferred lab routing, permission denial,
missing mandatory elements, and conflicting state transitions.
"""

import pytest
from unittest.mock import MagicMock, patch, call
from datetime import datetime, timedelta
from enum import Enum, auto
from dataclasses import dataclass, field
from typing import Optional, List


# ---------------------------------------------------------------------------
# Domain models (stand-ins for the real application layer)
# ---------------------------------------------------------------------------

class OrderStatus(Enum):
    DRAFT = auto()
    SUBMITTED = auto()
    ROUTED = auto()
    IN_PROGRESS = auto()
    COMPLETED = auto()
    CANCELLED = auto()
    REJECTED = auto()


class UserRole(Enum):
    CLINICIAN = auto()
    NURSE = auto()
    BILLING_CLERK = auto()
    PATIENT = auto()
    ADMIN = auto()


@dataclass
class LabFacility:
    lab_id: str
    name: str
    supported_tests: List[str]
    is_active: bool = True


@dataclass
class Patient:
    patient_id: str
    name: str
    preferred_lab_id: Optional[str] = None
    allergies: List[str] = field(default_factory=list)


@dataclass
class User:
    user_id: str
    role: UserRole
    name: str
    is_active: bool = True


@dataclass
class LabOrder:
    order_id: str
    patient_id: str
    ordering_clinician_id: str
    test_codes: List[str]
    priority: str                       # ROUTINE | STAT | URGENT
    clinical_indication: str
    specimen_type: str
    status: OrderStatus = OrderStatus.DRAFT
    routed_lab_id: Optional[str] = None
    created_at: datetime = field(default_factory=datetime.utcnow)
    submitted_at: Optional[datetime] = None
    notes: Optional[str] = None


class PermissionDeniedError(PermissionError):
    pass


class MissingMandatoryFieldError(ValueError):
    pass


class InvalidStateTransitionError(RuntimeError):
    pass


class PreferredLabUnavailableError(RuntimeError):
    pass


class LabNotFoundError(LookupError):
    pass


class DuplicateOrderError(RuntimeError):
    pass


# ---------------------------------------------------------------------------
# Service under test (interface / contract)
# ---------------------------------------------------------------------------

class LabOrderService:
    """
    Application service that encapsulates ordering logic.
    All dependencies are injected so they can be replaced with mocks.
    """

    MANDATORY_FIELDS = ["patient_id", "ordering_clinician_id", "test_codes",
                        "priority", "clinical_indication", "specimen_type"]
    VALID_PRIORITIES = {"ROUTINE", "STAT", "URGENT"}
    ALLOWED_ROLES = {UserRole.CLINICIAN}

    def __init__(self, order_repo, patient_repo, lab_repo,
                 auth_service, notification_service, audit_service):
        self._order_repo = order_repo
        self._patient_repo = patient_repo
        self._lab_repo = lab_repo
        self._auth = auth_service
        self._notifier = notification_service
        self._audit = audit_service

    # -- public API ----------------------------------------------------------

    def create_order(self, requesting_user: User, order_data: dict) -> LabOrder:
        self._check_permission(requesting_user, "create_order")
        self._validate_mandatory_fields(order_data)
        self._validate_priority(order_data["priority"])

        patient = self._patient_repo.get_by_id(order_data["patient_id"])
        order = LabOrder(
            order_id=self._order_repo.next_id(),
            patient_id=patient.patient_id,
            ordering_clinician_id=requesting_user.user_id,
            test_codes=order_data["test_codes"],
            priority=order_data["priority"],
            clinical_indication=order_data["clinical_indication"],
            specimen_type=order_data["specimen_type"],
            notes=order_data.get("notes"),
        )
        self._order_repo.save(order)
        self._audit.log("ORDER_CREATED", order.order_id, requesting_user.user_id)
        return order

    def submit_order(self, requesting_user: User, order_id: str) -> LabOrder:
        self._check_permission(requesting_user, "submit_order")
        order = self._order_repo.get_by_id(order_id)

        if order.status != OrderStatus.DRAFT:
            raise InvalidStateTransitionError(
                f"Cannot submit order in state {order.status.name}. "
                "Order must be in DRAFT state."
            )

        order.status = OrderStatus.SUBMITTED
        order.submitted_at = datetime.utcnow()
        self._order_repo.save(order)
        self._audit.log("ORDER_SUBMITTED", order.order_id, requesting_user.user_id)
        return order

    def route_order(self, requesting_user: User, order_id: str) -> LabOrder:
        self._check_permission(requesting_user, "route_order")
        order = self._order_repo.get_by_id(order_id)

        if order.status != OrderStatus.SUBMITTED:
            raise InvalidStateTransitionError(
                f"Cannot route order in state {order.status.name}. "
                "Order must be in SUBMITTED state."
            )

        patient = self._patient_repo.get_by_id(order.patient_id)
        target_lab = self._resolve_lab(patient, order.test_codes)

        order.routed_lab_id = target_lab.lab_id
        order.status = OrderStatus.ROUTED
        self._order_repo.save(order)
        self._notifier.notify_lab(target_lab.lab_id, order)
        self._audit.log("ORDER_ROUTED", order.order_id, requesting_user.user_id,
                        extra={"lab_id": target_lab.lab_id})
        return order

    def cancel_order(self, requesting_user: User, order_id: str,
                     reason: str) -> LabOrder:
        self._check_permission(requesting_user, "cancel_order")
        order = self._order_repo.get_by_id(order_id)

        if order.status in {OrderStatus.COMPLETED, OrderStatus.CANCELLED}:
            raise InvalidStateTransitionError(
                f"Cannot cancel order in state {order.status.name}."
            )

        order.status = OrderStatus.CANCELLED
        self._order_repo.save(order)
        self._audit.log("ORDER_CANCELLED", order.order_id,
                        requesting_user.user_id, extra={"reason": reason})
        return order

    # -- private helpers -----------------------------------------------------

    def _check_permission(self, user: User, action: str):
        if not user.is_active:
            raise PermissionDeniedError(f"User {user.user_id} account is inactive.")
        if user.role not in self.ALLOWED_ROLES:
            raise PermissionDeniedError(
                f"Role {user.role.name} is not authorised to perform '{action}'."
            )
        if not self._auth.has_permission(user.user_id, action):
            raise PermissionDeniedError(
                f"User {user.user_id} does not have permission: {action}."
            )

    def _validate_mandatory_fields(self, data: dict):
        missing = [f for f in self.MANDATORY_FIELDS if not data.get(f)]
        if missing:
            raise MissingMandatoryFieldError(
                f"Missing mandatory fields: {', '.join(missing)}"
            )

    def _validate_priority(self, priority: str):
        if priority not in self.VALID_PRIORITIES:
            raise MissingMandatoryFieldError(
                f"Invalid priority '{priority}'. "
                f"Must be one of {self.VALID_PRIORITIES}."
            )

    def _resolve_lab(self, patient: Patient,
                     test_codes: List[str]) -> LabFacility:
        if patient.preferred_lab_id:
            try:
                lab = self._lab_repo.get_by_id(patient.preferred_lab_id)
                if lab.is_active and all(
                    tc in lab.supported_tests for tc in test_codes
                ):
                    return lab
            except LabNotFoundError:
                pass  # fall through to default routing

        # Fallback: find any active lab that supports all requested tests
        available = self._lab_repo.find_labs_supporting_tests(test_codes)
        active = [lab for lab in available if lab.is_active]
        if not active:
            raise PreferredLabUnavailableError(
                "No active lab found that supports the requested tests."
            )
        return active[0]


