class TestCreateOrder:
    """Happy-path and validation tests for order creation."""

    def test_clinician_can_create_order_successfully(
        self, service, clinician, patient_with_preferred_lab,
        valid_order_data, mock_patient_repo, mock_order_repo, mock_audit
    ):
        """A clinician with correct permissions creates an order successfully."""
        mock_patient_repo.get_by_id.return_value = patient_with_preferred_lab

        order = service.create_order(clinician, valid_order_data)

        assert order.order_id == "ORD-001"
        assert order.status == OrderStatus.DRAFT
        assert order.patient_id == patient_with_preferred_lab.patient_id
        assert order.ordering_clinician_id == clinician.user_id
        assert order.test_codes == valid_order_data["test_codes"]
        mock_order_repo.save.assert_called_once_with(order)
        mock_audit.log.assert_called_once_with(
            "ORDER_CREATED", order.order_id, clinician.user_id
        )

    def test_created_order_persists_correct_priority(
        self, service, clinician, patient_with_preferred_lab,
        valid_order_data, mock_patient_repo
    ):
        mock_patient_repo.get_by_id.return_value = patient_with_preferred_lab
        for priority in ("ROUTINE", "STAT", "URGENT"):
            valid_order_data["priority"] = priority
            order = service.create_order(clinician, valid_order_data)
            assert order.priority == priority

    def test_order_notes_are_optional(
        self, service, clinician, patient_with_preferred_lab,
        valid_order_data, mock_patient_repo
    ):
        mock_patient_repo.get_by_id.return_value = patient_with_preferred_lab
        assert "notes" not in valid_order_data
        order = service.create_order(clinician, valid_order_data)
        assert order.notes is None

    def test_optional_notes_are_stored_when_provided(
        self, service, clinician, patient_with_preferred_lab,
        valid_order_data, mock_patient_repo
    ):
        mock_patient_repo.get_by_id.return_value = patient_with_preferred_lab
        valid_order_data["notes"] = "Patient is fasting."
        order = service.create_order(clinician, valid_order_data)
        assert order.notes == "Patient is fasting."


class TestPermissionDenial:
    """All permission-related negative paths."""

    @pytest.mark.parametrize("role", [
        UserRole.NURSE,
        UserRole.BILLING_CLERK,
        UserRole.PATIENT,
        UserRole.ADMIN,
    ])
    def test_non_clinician_roles_cannot_create_order(
        self, service, valid_order_data, mock_patient_repo,
        patient_with_preferred_lab, role
    ):
        """Only clinicians are authorised to create lab orders."""
        mock_patient_repo.get_by_id.return_value = patient_with_preferred_lab
        non_clinician = User(user_id="USR-NC-01", role=role, name="Other User")
        with pytest.raises(PermissionDeniedError, match=f"{role.name}"):
            service.create_order(non_clinician, valid_order_data)

    def test_inactive_clinician_cannot_create_order(
        self, service, valid_order_data
    ):
        inactive = User(user_id="USR-CL-99", role=UserRole.CLINICIAN,
                        name="Retired Dr.", is_active=False)
        with pytest.raises(PermissionDeniedError, match="inactive"):
            service.create_order(inactive, valid_order_data)

    def test_clinician_without_explicit_permission_cannot_create_order(
        self, service, valid_order_data, mock_auth
    ):
        """Auth service denies a specific action even for a clinician role."""
        mock_auth.has_permission.return_value = False
        clinician = User(user_id="USR-CL-02", role=UserRole.CLINICIAN,
                         name="Dr. No Permission")
        with pytest.raises(PermissionDeniedError, match="create_order"):
            service.create_order(clinician, valid_order_data)

    def test_permission_check_is_called_before_validation(
        self, service, mock_auth
    ):
        """Authorisation gate fires before field validation."""
        mock_auth.has_permission.return_value = False
        non_clinician = User(user_id="USR-NC-02", role=UserRole.BILLING_CLERK,
                             name="Billing Clerk")
        incomplete_data = {}        # intentionally missing everything
        with pytest.raises(PermissionDeniedError):
            service.create_order(non_clinician, incomplete_data)

    @pytest.mark.parametrize("action", [
        "submit_order", "route_order", "cancel_order"
    ])
    def test_non_clinician_cannot_perform_order_lifecycle_actions(
        self, service, action, mock_auth, draft_order, submitted_order,
        mock_order_repo, patient_with_preferred_lab, mock_patient_repo,
        preferred_lab, mock_lab_repo
    ):
        """Permission denial is enforced on every order lifecycle endpoint."""
        non_clinician = User(user_id="USR-NC-03", role=UserRole.NURSE,
                             name="Nurse Ratchet")
        mock_order_repo.get_by_id.return_value = draft_order
        with pytest.raises(PermissionDeniedError):
            getattr(service, action)(non_clinician, "ORD-001",
                                     **({"reason": "test"} if action == "cancel_order" else {}))


class TestMissingMandatoryElements:
