class TestPreferredLabRouting:
    """Routing logic — preferred lab selected when available and capable."""

    def test_order_routes_to_preferred_lab_when_available(
        self, service, clinician, patient_with_preferred_lab,
        preferred_lab, submitted_order, mock_order_repo,
        mock_patient_repo, mock_lab_repo, mock_notifier, mock_audit
    ):
        mock_order_repo.get_by_id.return_value = submitted_order
        mock_patient_repo.get_by_id.return_value = patient_with_preferred_lab
